            UPDATE public.utm_visualization
      SET aggregation= $$
{
  "metrics": [
    {
      "id": "1",
      "aggregation": "COUNT",
      "field": "",
      "customLabel": ""
    }
  ],
  "bucket": {
    "id": "1000",
    "aggregation": "TERMS",
    "type": "AXIS",
    "field": "origin.ip.keyword",
    "customLabel": "IP",
    "terms": {
